+		{"1.2.3", "1.2.3-alpha", 1},       // release > pre-release
+		{"1.2.3-alpha", "1.2.3-beta", -1}, // alpha < beta
+		{"1.2.3-beta", "1.2.3-alpha", 1},  // beta > alpha
