+func compareVersionStrings(a, b string) int {
+	if a == b {
+		return 0
+	}
+	if a == "" {
+		return -1
+	}
+	if b == "" {
+		return 1
+	}
+
+	aParts := versionParts(a)
+	bParts := versionParts(b)
+	maxLen := len(aParts)
+	if len(bParts) > maxLen {
+		maxLen = len(bParts)
+	}
+	for i := 0; i < maxLen; i++ {
+		aExists := i < len(aParts)
+		bExists := i < len(bParts)
+		aPart, bPart := "0", "0"
+		if aExists {
+			aPart = aParts[i]
+		}
+		if bExists {
+			bPart = bParts[i]
+		}
+		aNum, aErr := strconv.Atoi(aPart)
+		bNum, bErr := strconv.Atoi(bPart)
+		if aErr == nil && bErr == nil {
+			if aNum != bNum {
+				if aNum > bNum {
+					return 1
+				}
+				return -1
+			}
+			continue
+		}
+		// One or both segments are non-numeric (pre-release identifiers such as
+		// "alpha", "beta", "rc1"). Per semver, a version that has a pre-release
+		// segment at a position where the other version has no segment at all is
+		// the lower-precedence version (e.g. 1.2.3-alpha < 1.2.3).
+		if aErr != nil && !bExists {
+			return -1
+		}
+		if bErr != nil && !aExists {
+			return 1
+		}
+		if aPart != bPart {
+			if aPart > bPart {
+				return 1
