318	+	}
319	+
320	+	usedGroupIDs := make(map[string]bool)
321	+	result := &FetchedSkills{}
322	+	for _, skill := range syncableSkills {
323	+		for _, groupID := range skill.GroupIDs {
324	+			usedGroupIDs[groupID] = true
325	+		}
326	+		if skill.Required {
327	+			result.Required = append(result.Required, skill)
328	+		} else {
329	+			result.Optional = append(result.Optional, skill)
330	+		}
331	+	}
