502	+func compareVersionStrings(a, b string) int {
503	+	if a == b {
504	+		return 0
505	+	}
506	+	if a == "" {
507	+		return -1
508	+	}
509	+	if b == "" {
510	+		return 1
511	+	}
512	+
513	+	aParts := versionParts(a)
514	+	bParts := versionParts(b)
515	+	maxLen := len(aParts)
516	+	if len(bParts) > maxLen {
517	+		maxLen = len(bParts)
518	+	}
519	+	for i := 0; i < maxLen; i++ {
520	+		aExists := i < len(aParts)
521	+		bExists := i < len(bParts)
522	+		aPart, bPart := "0", "0"
523	+		if aExists {
524	+			aPart = aParts[i]
525	+		}
526	+		if bExists {
527	+			bPart = bParts[i]
528	+		}
529	+		aNum, aErr := strconv.Atoi(aPart)
530	+		bNum, bErr := strconv.Atoi(bPart)
531	+		if aErr == nil && bErr == nil {
532	+			if aNum != bNum {
533	+				if aNum > bNum {
534	+					return 1
535	+				}
536	+				return -1
537	+			}
538	+			continue
539	+		}
540	+		// One or both segments are non-numeric (pre-release identifiers such as
541	+		// "alpha", "beta", "rc1"). Per semver, a version that has a pre-release
542	+		// segment at a position where the other version has no segment at all is
543	+		// the lower-precedence version (e.g. 1.2.3-alpha < 1.2.3).
544	+		if aErr != nil && !bExists {
545	+			return -1
546	+		}
547	+		if bErr != nil && !aExists {
548	+			return 1
549	+		}
550	+		if aPart != bPart {
551	+			if aPart > bPart {
552	+				return 1
553	+			}
554	+			return -1
555	+		}
556	+	}
557	+	return 0
558	+}
