560	+func versionParts(version string) []string {
561	+	return strings.FieldsFunc(version, func(r rune) bool {
562	+		return !(r >= '0' && r <= '9') && !(r >= 'A' && r <= 'Z') && !(r >= 'a' && r <= 'z')
563	+	})
564	+}
