+func relationIDs(raw interface{}) []string {
+	switch v := raw.(type) {
+	case string:
+		if v == "" {
+			return nil
+		}
+		return []string{v}
+	case map[string]interface{}:
+		if id := stringFromMap(v, "identifier"); id != "" {
+			return []string{id}
+		}
+	case []interface{}:
+		var ids []string
+		for _, item := range v {
+			ids = append(ids, relationIDs(item)...)
+		}
+		return ids
+	}
+	return nil
+}
