func TestLoadLegacySkillContent_OnlyFetchesSelectedSkills(t *testing.T) {
	var requestBodies []map[string]interface{}
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.URL.Path == "/auth/access_token" {
			json.NewEncoder(w).Encode(map[string]interface{}{"ok": true, "accessToken": "tok", "expiresIn": 3600})
			return
		}
		// skill_version blueprint missing → triggers legacy fallback
		if r.URL.Path == "/blueprints/skill_version/entities/search" {
			w.WriteHeader(http.StatusNotFound)
			json.NewEncoder(w).Encode(map[string]interface{}{
				"ok": false, "error": "blueprint_not_found",
				"message": "Blueprint skill_version does not exist",
			})
			return
		}
		var body map[string]interface{}
		if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
			t.Fatalf("decode body: %v", err)
		}
		requestBodies = append(requestBodies, body)
		json.NewEncoder(w).Encode(map[string]interface{}{
			"ok": true,
			"entities": []map[string]interface{}{
				{"identifier": "selected", "properties": map[string]interface{}{"instructions": "hello"}},
			},
		})
	}))
	defer server.Close()

	client := api.NewClient(api.ClientOpts{ClientID: "id", ClientSecret: "secret", APIURL: server.URL, Timeout: 0})
	skills, err := LoadLatestVersionFiles(context.Background(), client, []Skill{
		{Identifier: "selected", Title: "Selected"},
	})
	if err != nil {
		t.Fatalf("LoadLatestVersionFiles: %v", err)
	}
	if len(skills) != 1 {
		t.Fatalf("expected 1 skill, got %d", len(skills))
	}

	// The legacy skill search must filter to only the selected skill identifiers.
	if len(requestBodies) == 0 {
		t.Fatal("expected at least one search request body")
	}
	body := requestBodies[0]
	query, _ := body["query"].(map[string]interface{})
	rules, _ := query["rules"].([]interface{})
	if len(rules) == 0 {
		t.Fatal("expected filter rules in legacy skill search, got none (fetches all skills)")
	}
	rule := rules[0].(map[string]interface{})
	if rule["property"] != "$identifier" {
		t.Errorf("expected $identifier filter, got %v", rule["property"])
	}
}

